select count(*) from postgres.comments as c, postgres.posthistory as ph, postgres.votes as v, postgres.users as u where v.userid = u.id and c.userid = u.id and ph.userid = u.id and c.score=0 and c.creationdate>=timestamp '2010-07-19 19:56:21' and c.creationdate<=timestamp '2014-09-11 13:36:12' and u.views<=433 and u.downvotes>=0 and u.creationdate<=timestamp '2014-09-12 21:37:39';
